// In stats_models/src/lib.rs, as a private helper function

/// Calculates common goodness-of-fit statistics.
fn calculate_gof_stats(
    y: &[f64],
    residuals: &[f64],
    n_obs: usize,
    df_resid: usize,
) -> (f64, f64, f64) { // Returns (tss, r_squared, adj_r_squared)
    let rss: f64 = residuals.iter().map(|r| r * r).sum();
    if n_obs == 0 {
        return (0.0, 0.0, 0.0);
    }
    let y_mean = y.iter().sum::<f64>() / n_obs as f64;
    let tss: f64 = y.iter().map(|val| (val - y_mean).powi(2)).sum();

    let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };

    let n = n_obs as f64;
    // Number of parameters p = n_obs - df_resid
    let p = (n_obs - df_resid) as f64;
    let adj_r_squared = if n > 1.0 && p > 0.0 && (n - 1.0) > 0.0 {
        1.0 - (rss / df_resid as f64) / (tss / (n - 1.0))
    } else {
        r_squared
    };

    (tss, r_squared, adj_r_squared)
}

// You would then call this from each `summary` method. This requires
// storing the original `y` vector in the `LmFit` and `GlmFit` structs.
